import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../services/api';
import toast from 'react-hot-toast';

const ForgotPasswordPage = () => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!email.trim()) {
      toast.error('Please enter your email');
      return;
    }

    setLoading(true);

    try {
      const response = await api.post('/auth/forgot-password', { email });
      console.log('Forgot password response:', response);
      
      toast.success('Password reset link sent to your email!');
      setSubmitted(true);
      
      // Redirect to login after 3 seconds
      setTimeout(() => {
        navigate('/login');
      }, 3000);
    } catch (err) {
      console.error('Forgot password error:', err);
      const errorMsg = err.response?.data?.message || 'Failed to process request. Please try again.';
      toast.error(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  if (submitted) {
    return (
      <div className="container">
        <div className="auth-container" style={{textAlign: 'center'}}>
          <h1>Check Your Email</h1>
          <p style={{fontSize: '16px', lineHeight: '1.6', color: '#666', marginBottom: '20px'}}>
            We've sent a password reset link to <strong>{email}</strong>
          </p>
          <p style={{fontSize: '14px', color: '#999'}}>
            Please check your email and click the link to reset your password.
          </p>
          <p style={{fontSize: '14px', color: '#999', marginTop: '20px'}}>
            Redirecting to login in 3 seconds...
          </p>
          <Link to="/login" className="btn btn-primary" style={{marginTop: '20px', display: 'inline-block'}}>
            Back to Login
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="auth-container">
        <h1>Reset Password</h1>
        
        <p style={{fontSize: '14px', color: '#666', marginBottom: '20px'}}>
          Enter your email address and we'll send you a link to reset your password.
        </p>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Email Address</label>
            <input
              type="email"
              className="form-control"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
            />
          </div>

          <button
            type="submit"
            className="btn btn-primary btn-block"
            disabled={loading}
          >
            {loading ? 'Sending...' : 'Send Reset Link'}
          </button>
        </form>

        <p className="text-center mt-2">
          Remember your password?{' '}
          <Link to="/login">Login</Link>
        </p>
      </div>
    </div>
  );
};

export default ForgotPasswordPage;
